import { Button } from '@/components/ui/button';
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from '@/components/ui/dropdown-menu';
import { IDocumentInfo } from '@/interfaces/database/document';
import { useCallback } from 'react';
import { useTranslation } from 'react-i18next';
import { DocumentType } from './constant';
import { UseChangeDocumentParserShowType } from './use-change-document-parser';
import { UseSaveMetaShowType } from './use-save-meta';

export function ParsingMethodCell({
  record,
  showChangeParserModal,
  showSetMetaModal,
}: { record: IDocumentInfo } & UseChangeDocumentParserShowType &
  UseSaveMetaShowType) {
  const { t } = useTranslation();
  const parserLabel =
    record.parser_id === 'naive' ? 'general' : record.parser_id;
  const isVirtualDocument = record.type === DocumentType.Virtual;

  const handleShowChangeParserModal = useCallback(() => {
    showChangeParserModal(record);
  }, [record, showChangeParserModal]);

  const handleShowSetMetaModal = useCallback(() => {
    showSetMetaModal(record);
  }, [record, showSetMetaModal]);

  if (isVirtualDocument) {
    return <span className="text-xs text-[#9ca3af]">-</span>;
  }

  return (
    <DropdownMenu>
      <DropdownMenuTrigger asChild>
        <Button
          variant={'transparent'}
          className="h-7 border-none px-1 text-xs font-medium text-[#6b7280] hover:text-[#111827]"
          size={'sm'}
        >
          {parserLabel}
        </Button>
      </DropdownMenuTrigger>
      <DropdownMenuContent align="start" className="p-1">
        <DropdownMenuItem
          onClick={handleShowChangeParserModal}
          justifyBetween={false}
          className="text-[13px] font-medium justify-start gap-2 text-[#111827]"
        >
          {t('knowledgeDetails.chunkMethod')}
        </DropdownMenuItem>
        <DropdownMenuItem
          onClick={handleShowSetMetaModal}
          justifyBetween={false}
          className="text-[13px] font-medium justify-start gap-2 text-[#111827]"
        >
          {t('knowledgeDetails.setMetaData')}
        </DropdownMenuItem>
      </DropdownMenuContent>
    </DropdownMenu>
  );
}
