import { BulkOperateBar } from '@/components/bulk-operate-bar';
import { FileUploadDialog } from '@/components/file-upload-dialog';
import { RenameDialog } from '@/components/rename-dialog';
import { Button } from '@/components/ui/button';
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from '@/components/ui/dropdown-menu';
import { SearchInput } from '@/components/ui/input';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import { useRowSelection } from '@/hooks/logic-hooks/use-row-selection';
import { useGetKnowledgeSearchParams } from '@/hooks/route-hook';
import { useFetchDocumentList } from '@/hooks/use-document-request';
import { listDocument } from '@/services/knowledge-service';
import { RowSelectionState } from '@tanstack/react-table';
import { Loader2, Upload } from 'lucide-react';
import { useCallback, useMemo, useState } from 'react';
import { useTranslation } from 'react-i18next';
import { toast } from 'sonner';
import { useParams } from 'umi';
import { DatasetTable } from './dataset-table';
import Generate from './generate';
import styles from './index.less';
import { useBulkOperateDataset } from './use-bulk-operate-dataset';
import { useCreateEmptyDocument } from './use-create-empty-document';
import { useSelectDatasetFilters } from './use-select-filters';
import { useHandleUploadDocument } from './use-upload-document';

export default function Dataset() {
  const { t } = useTranslation();
  const {
    documentUploadVisible,
    hideDocumentUploadModal,
    showDocumentUploadModal,
    onDocumentUploadOk,
    documentUploadLoading,
  } = useHandleUploadDocument();

  const {
    searchString,
    documents,
    pagination,
    handleInputChange,
    setPagination,
    filterValue,
    handleFilterSubmit,
    loading,
  } = useFetchDocumentList();
  const { knowledgeId } = useGetKnowledgeSearchParams();
  const { id } = useParams();
  const [selectingAll, setSelectingAll] = useState(false);
  const { fileTypes, fileStatus } = useSelectDatasetFilters();

  const {
    createLoading,
    onCreateOk,
    createVisible,
    hideCreateModal,
    showCreateModal,
  } = useCreateEmptyDocument();

  const { rowSelection, rowSelectionIsEmpty, setRowSelection, selectedCount } =
    useRowSelection();

  const { list } = useBulkOperateDataset({
    documents,
    rowSelection,
    setRowSelection,
  });

  const allSelected = useMemo(() => {
    const total = pagination.total || 0;
    return total > 0 && selectedCount >= total;
  }, [pagination.total, selectedCount]);

  const handleClearSelection = useCallback(() => {
    setRowSelection({});
  }, [setRowSelection]);

  const handleSelectAll = useCallback(async () => {
    if (selectingAll || allSelected) {
      return;
    }
    const kbId = knowledgeId || id;
    if (!kbId || !pagination.total) {
      return;
    }
    setSelectingAll(true);
    try {
      const pageSize = 500;
      let page = 1;
      const ids = new Set<string>();
      let total = pagination.total;

      while (ids.size < total) {
        const ret = await listDocument(
          {
            kb_id: kbId,
            keywords: searchString,
            page,
            page_size: pageSize,
          },
          {
            suffix: filterValue.type,
            run_status: filterValue.run,
          },
        );
        if (ret?.data?.code !== 0) {
          throw new Error(ret?.data?.message || 'Failed to fetch documents');
        }

        const data = ret?.data?.data;
        const docs = data?.docs ?? [];
        total = data?.total ?? total;
        docs.forEach((doc: { id: string }) => ids.add(doc.id));

        if (docs.length < pageSize) {
          break;
        }
        page += 1;
      }

      const nextSelection: RowSelectionState = {};
      ids.forEach((docId) => {
        nextSelection[docId] = true;
      });
      setRowSelection(nextSelection);
    } catch (error) {
      console.warn(error);
      toast.error('Select all failed');
    } finally {
      setSelectingAll(false);
    }
  }, [
    allSelected,
    filterValue.run,
    filterValue.type,
    id,
    knowledgeId,
    pagination.total,
    searchString,
    selectingAll,
    setRowSelection,
  ]);

  const selectedFileType = filterValue.type?.[0] || 'all';

  const handleFileTypeChange = useCallback(
    (value: string) => {
      handleFilterSubmit({
        ...filterValue,
        type: value === 'all' ? [] : [value],
      });
    },
    [filterValue, handleFilterSubmit],
  );

  return (
    <>
      <section className={styles.page}>
        <div className={styles.toolbar}>
          <div className={styles.toolbarTitle}>
            <div className={styles.toolbarTitleMain}>
              {t('knowledgeDetails.dataset')}
            </div>
            <div className={styles.toolbarTitleSub}>
              {t('knowledgeDetails.datasetDescription')}
            </div>
          </div>
        </div>

        <div className={styles.listSurface}>
          <div className={styles.filterRow}>
            <div className={styles.filterControls}>
              <SearchInput
                value={searchString}
                onChange={handleInputChange}
                className={styles.searchInput}
                placeholder={t('knowledgeDetails.searchByName', {
                  defaultValue: '输入文件名称/标签搜索',
                })}
              />
              <Select
                value={selectedFileType}
                onValueChange={handleFileTypeChange}
              >
                <SelectTrigger className={styles.fileTypeSelect}>
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="all">
                    {t('knowledgeDetails.all', { defaultValue: '全部文件' })}
                  </SelectItem>
                  {fileTypes.map((item) => (
                    <SelectItem key={item.id} value={item.id}>
                      {item.label} ({item.count})
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>
            <div className={styles.toolbarActions}>
              <Generate buttonClassName={styles.secondaryActionButton} />
              <DropdownMenu>
                <DropdownMenuTrigger asChild>
                  <Button size={'sm'} className={styles.primaryActionButton}>
                    <Upload className="size-4" />
                    {t('knowledgeDetails.addFile')}
                  </Button>
                </DropdownMenuTrigger>
                <DropdownMenuContent className="w-56">
                  <DropdownMenuItem onClick={showDocumentUploadModal}>
                    {t('fileManager.uploadFile')}
                  </DropdownMenuItem>
                  <DropdownMenuSeparator />
                  <DropdownMenuItem onClick={showCreateModal}>
                    {t('knowledgeDetails.emptyFiles')}
                  </DropdownMenuItem>
                </DropdownMenuContent>
              </DropdownMenu>
            </div>
          </div>

          {rowSelectionIsEmpty || (
            <BulkOperateBar
              list={list}
              count={selectedCount}
              extra={
                <>
                  <Button
                    variant="outline"
                    size="sm"
                    onClick={handleClearSelection}
                    disabled={selectedCount === 0}
                  >
                    {t('common.clear', { defaultValue: 'Clear selection' })}
                  </Button>
                  <Button
                    size="sm"
                    onClick={handleSelectAll}
                    disabled={allSelected || selectingAll}
                  >
                    {selectingAll ? (
                      <>
                        <Loader2 className="mr-2 size-4 animate-spin" />
                        {t('common.loading', { defaultValue: 'Selecting...' })}
                      </>
                    ) : allSelected ? (
                      t('common.allSelected', { defaultValue: 'All selected' })
                    ) : (
                      `${t('common.selectAll', { defaultValue: 'Select all' })} (${
                        pagination.total ?? 0
                      })`
                    )}
                  </Button>
                </>
              }
            ></BulkOperateBar>
          )}
          <div className={styles.tableCard}>
            <DatasetTable
              documents={documents}
              pagination={pagination}
              setPagination={setPagination}
              rowSelection={rowSelection}
              setRowSelection={setRowSelection}
              loading={loading}
              runStatusFilters={fileStatus}
              filterValue={filterValue}
              handleFilterSubmit={handleFilterSubmit}
              containerClassName={styles.tableContainer}
              tableRootClassName={styles.tableRoot}
              paginationClassName={styles.tablePagination}
            ></DatasetTable>
          </div>
        </div>
        {documentUploadVisible && (
          <FileUploadDialog
            hideModal={hideDocumentUploadModal}
            onOk={onDocumentUploadOk}
            loading={documentUploadLoading}
            showParseOnCreation
          ></FileUploadDialog>
        )}
        {createVisible && (
          <RenameDialog
            hideModal={hideCreateModal}
            onOk={onCreateOk}
            loading={createLoading}
            title={'File Name'}
          ></RenameDialog>
        )}
      </section>
    </>
  );
}
