import {
  HoverCard,
  HoverCardContent,
  HoverCardTrigger,
} from '@/components/ui/hover-card';
import { Progress } from '@/components/ui/progress';
import { getAgenticDeepReadStatusLabel } from '@/constants/agentic-deepread';
import { IDocumentInfo } from '@/interfaces/database/document';
import { DocumentType } from './constant';
import { ParsingCard, PopoverContent } from './parsing-card';
import { isParserRunning } from './utils';

function DeepReadStatusBadge({ record }: { record: IDocumentInfo }) {
  const deepreadState = record.parser_config?.agentic_deepread;
  const showDeepRead = Boolean(
    record.parser_config?.agentic_deepread_prebuild ||
      deepreadState?.status ||
      deepreadState?.artifact_path,
  );
  if (!showDeepRead) {
    return null;
  }

  const status = deepreadState?.status;
  const statusLabel = getAgenticDeepReadStatusLabel(status);
  const colorClass =
    status === 'ready'
      ? 'bg-[#ecfdf3] text-[#059669]'
      : status === 'fallback'
        ? 'bg-[#fff7e6] text-[#d48806]'
        : status === 'failed'
          ? 'bg-[#fef2f2] text-[#dc2626]'
          : 'bg-[#eef4ff] text-[#2563eb]';

  return (
    <span
      className={`ml-2 inline-flex items-center rounded-md px-2 py-1 text-[11px] font-medium ${colorClass}`}
    >
      DeepRead {statusLabel}
    </span>
  );
}

export function ParsingStatusCell({ record }: { record: IDocumentInfo }) {
  const { run, progress } = record;
  const p = Number((progress * 100).toFixed(2));
  const showParse = record.type !== DocumentType.Virtual;

  return (
    <section className="flex items-center">
      {showParse && (
        <>
          {isParserRunning(run, progress) ? (
            <HoverCard>
              <HoverCardTrigger asChild>
                <div className="flex items-center gap-1 min-w-[86px]">
                  <Progress value={p} className="h-1 flex-1 min-w-10" />
                  {p}%
                </div>
              </HoverCardTrigger>
              <HoverCardContent className="w-[40vw]">
                <PopoverContent record={record}></PopoverContent>
              </HoverCardContent>
            </HoverCard>
          ) : (
            <div className="flex items-center">
              <ParsingCard record={record}></ParsingCard>
              <DeepReadStatusBadge record={record} />
            </div>
          )}
        </>
      )}
      {showParse || <span className="text-xs text-[#9ca3af]">-</span>}
    </section>
  );
}
