import { IDocumentInfo } from '@/interfaces/database/document';

export type OcrReviewDisplayStatus = 'pending_review' | null;

export const getOcrReviewDisplayStatus = (
  doc?: Partial<IDocumentInfo>,
): OcrReviewDisplayStatus => {
  if (!doc || doc.type !== 'pdf') {
    return null;
  }

  const review = doc.parser_config?.ocr_review;
  if (!review?.review_required) {
    return null;
  }

  const status = String(review.status || '').toLowerCase();
  if (status === 'reviewing') {
    return 'pending_review';
  }

  return null;
};
