import { Button } from '@/components/ui/button';
import {
  HoverCard,
  HoverCardContent,
  HoverCardTrigger,
} from '@/components/ui/hover-card';
import { getAgenticDeepReadStatusLabel } from '@/constants/agentic-deepread';
import { IDocumentInfo } from '@/interfaces/database/document';
import { cn } from '@/lib/utils';
import { getOcrReviewDisplayStatus } from '@/utils/ocr-review-display';
import { useTranslation } from 'react-i18next';
import reactStringReplace from 'react-string-replace';
import { RunningStatus, RunningStatusMap } from './constant';

interface IProps {
  record: IDocumentInfo;
}

function Dot({
  run,
  pendingReview,
}: {
  run: RunningStatus;
  pendingReview?: boolean;
}) {
  if (pendingReview) {
    return (
      <span
        className={'size-1 inline-block rounded'}
        style={{ backgroundColor: '#d48806' }}
      ></span>
    );
  }
  const runningStatus = RunningStatusMap[run];
  return (
    <span
      className={'size-1 inline-block rounded'}
      style={{ backgroundColor: runningStatus.color }}
    ></span>
  );
}

export const PopoverContent = ({ record }: IProps) => {
  const { t } = useTranslation();
  const reviewDisplayStatus = getOcrReviewDisplayStatus(record);
  const isPendingReview = reviewDisplayStatus === 'pending_review';
  const label = isPendingReview
    ? t('knowledgeDetails.runningStatus5')
    : t(`knowledgeDetails.runningStatus${record.run}`);
  const deepreadState = record.parser_config?.agentic_deepread;
  const showDeepRead = Boolean(
    record.parser_config?.agentic_deepread_prebuild ||
      deepreadState?.status ||
      deepreadState?.artifact_path,
  );

  const replaceText = (text: string) => {
    // Remove duplicate \n
    const nextText = text.replace(/(\n)\1+/g, '$1');

    const replacedText = reactStringReplace(
      nextText,
      /(\[ERROR\].+\s)/g,
      (match, i) => {
        return (
          <span key={i} className={'text-red-600'}>
            {match}
          </span>
        );
      },
    );

    return replacedText;
  };

  const items = [
    {
      key: 'process_begin_at',
      label: t('knowledgeDetails.processBeginAt'),
      children: record.process_begin_at,
    },
    {
      key: 'knowledgeDetails.process_duration',
      label: t('processDuration'),
      children: `${record.process_duration.toFixed(2)} s`,
    },
    {
      key: 'progress_msg',
      label: t('knowledgeDetails.progressMsg'),
      children: replaceText(record.progress_msg.trim()),
    },
    ...(showDeepRead
      ? [
          {
            key: 'agentic_deepread_status',
            label: 'DeepRead status',
            children: getAgenticDeepReadStatusLabel(deepreadState?.status),
          },
          {
            key: 'agentic_deepread_path',
            label: 'DeepRead corpus',
            children: deepreadState?.corpus_path || '-',
          },
          {
            key: 'agentic_deepread_artifact_path',
            label: 'DeepRead artifact',
            children: deepreadState?.artifact_path || '-',
          },
          {
            key: 'agentic_deepread_artifact_kind',
            label: 'DeepRead artifact kind',
            children: deepreadState?.artifact_kind || '-',
          },
          {
            key: 'agentic_deepread_fallback',
            label: 'DeepRead fallback',
            children: deepreadState?.fallback_kind || '-',
          },
        ]
      : []),
  ];

  return (
    <section>
      <div className="flex gap-2 items-center pb-2">
        <Dot run={record.run} pendingReview={isPendingReview}></Dot> {label}
      </div>
      <div className="flex flex-col max-h-[50vh] overflow-auto">
        {items.map((x, idx) => {
          return (
            <div key={x.key} className={idx < 2 ? 'flex gap-2' : ''}>
              <b>{x.label}:</b>
              <div className={'w-full  whitespace-pre-line text-wrap '}>
                {x.children}
              </div>
            </div>
          );
        })}
      </div>
    </section>
  );
};

export function ParsingCard({ record }: IProps) {
  const { t } = useTranslation();
  const reviewDisplayStatus = getOcrReviewDisplayStatus(record);
  const isPendingReview = reviewDisplayStatus === 'pending_review';
  const statusLabel = isPendingReview
    ? t('knowledgeDetails.runningStatus5')
    : t(`knowledgeDetails.runningStatus${record.run}`);

  return (
    <HoverCard>
      <HoverCardTrigger asChild>
        <Button
          variant={'transparent'}
          className={cn(
            'h-7 rounded-md border border-transparent px-2 text-xs font-medium hover:opacity-90',
            {
              'bg-[#ecfdf3] text-[#059669]': record.run === RunningStatus.DONE,
              'bg-[#eef4ff] text-[#2563eb]':
                record.run === RunningStatus.RUNNING ||
                record.run === RunningStatus.UNSTART ||
                record.run === RunningStatus.CANCEL,
              'bg-[#fef2f2] text-[#dc2626]': record.run === RunningStatus.FAIL,
              'bg-[#fff7e6] text-[#d48806]': isPendingReview,
            },
          )}
          size={'sm'}
        >
          <Dot run={record.run} pendingReview={isPendingReview}></Dot>
          <span className="ml-1">{statusLabel}</span>
        </Button>
      </HoverCardTrigger>
      <HoverCardContent className="w-[40vw]">
        <PopoverContent record={record}></PopoverContent>
      </HoverCardContent>
    </HoverCard>
  );
}
