import { ConfirmDeleteDialog } from '@/components/confirm-delete-dialog';
import { Button } from '@/components/ui/button';
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog';
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from '@/components/ui/dropdown-menu';
import { DocumentType } from '@/constants/knowledge';
import { useRemoveDocument } from '@/hooks/use-document-request';
import { IDocumentInfo } from '@/interfaces/database/document';
import { cn } from '@/lib/utils';
import { formatFileSize } from '@/utils/common-util';
import { formatDate } from '@/utils/date';
import { downloadDocument } from '@/utils/file-util';
import {
  Download,
  Eye,
  MoreHorizontal,
  PenLine,
  RefreshCw,
  Trash2,
} from 'lucide-react';
import { Fragment, useCallback, useState } from 'react';
import { useTranslation } from 'react-i18next';
import { UseRenameDocumentShowType } from './use-rename-document';
import { useHandleRunDocumentByIds } from './use-run-document';
import { isParserRunning } from './utils';

const Fields = ['name', 'size', 'type', 'create_time', 'update_time'];

const FunctionMap = {
  size: formatFileSize,
  create_time: formatDate,
  update_time: formatDate,
};

export function DatasetActionCell({
  record,
  showRenameModal,
}: { record: IDocumentInfo } & UseRenameDocumentShowType) {
  const { t } = useTranslation();
  const [viewOpen, setViewOpen] = useState(false);
  const { id, run, type, chunk_num, progress } = record;
  const isRunning = isParserRunning(run, progress);
  const isVirtualDocument = type === DocumentType.Virtual;
  const { handleRunDocumentByIds, loading: reparseLoading } =
    useHandleRunDocumentByIds(id);

  const { removeDocument } = useRemoveDocument();

  const onDownloadDocument = useCallback(() => {
    downloadDocument({
      id,
      filename: record.name,
    });
  }, [id, record.name]);

  const handleRemove = useCallback(() => {
    removeDocument(id);
  }, [id, removeDocument]);

  const handleRename = useCallback(() => {
    showRenameModal(record);
  }, [record, showRenameModal]);

  const handleViewOpen = useCallback(() => {
    setViewOpen(true);
  }, []);

  const handleReparse = useCallback(
    (shouldDelete: boolean = false) =>
      () => {
        handleRunDocumentByIds(id, isRunning, shouldDelete);
      },
    [handleRunDocumentByIds, id, isRunning],
  );

  return (
    <section className="flex items-center">
      <DropdownMenu modal={false}>
        <DropdownMenuTrigger asChild>
          <Button
            variant="transparent"
            className="border-none hover:bg-[#eff4ff] text-[#315efb] size-7 p-0"
            size={'sm'}
            aria-label={t('common.action', { defaultValue: '操作' })}
          >
            <MoreHorizontal className="size-4" />
          </Button>
        </DropdownMenuTrigger>
        <DropdownMenuContent align="end" className="w-[136px] p-1">
          {isVirtualDocument || (
            <>
              {chunk_num > 0 ? (
                <ConfirmDeleteDialog
                  title={t(`knowledgeDetails.redo`, { chunkNum: chunk_num })}
                  onOk={handleReparse(true)}
                  onCancel={handleReparse(false)}
                >
                  <DropdownMenuItem
                    onSelect={(event) => event.preventDefault()}
                    disabled={isRunning || reparseLoading}
                    justifyBetween={false}
                    className="text-[13px] font-medium justify-start gap-2 text-[#111827]"
                  >
                    <RefreshCw
                      className={cn('size-3.5', {
                        'animate-spin': reparseLoading,
                      })}
                    />
                    {t('knowledgeDetails.redoAction', {
                      defaultValue: '重新解析',
                    })}
                  </DropdownMenuItem>
                </ConfirmDeleteDialog>
              ) : (
                <DropdownMenuItem
                  onClick={handleReparse(false)}
                  disabled={isRunning || reparseLoading}
                  justifyBetween={false}
                  className="text-[13px] font-medium justify-start gap-2 text-[#111827]"
                >
                  <RefreshCw
                    className={cn('size-3.5', {
                      'animate-spin': reparseLoading,
                    })}
                  />
                  {t('knowledgeDetails.redoAction', {
                    defaultValue: '重新解析',
                  })}
                </DropdownMenuItem>
              )}
            </>
          )}
          <DropdownMenuItem
            onClick={handleRename}
            disabled={isRunning}
            justifyBetween={false}
            className="text-[13px] font-medium justify-start gap-2 text-[#111827]"
          >
            <PenLine className="size-3.5" />
            {t('common.rename', { defaultValue: '重命名' })}
          </DropdownMenuItem>
          <DropdownMenuItem
            onClick={handleViewOpen}
            disabled={isRunning}
            justifyBetween={false}
            className="text-[13px] font-medium justify-start gap-2 text-[#111827]"
          >
            <Eye className="size-3.5" />
            {t('common.view', { defaultValue: '查看' })}
          </DropdownMenuItem>
          {isVirtualDocument || (
            <DropdownMenuItem
              onClick={onDownloadDocument}
              disabled={isRunning}
              justifyBetween={false}
              className="text-[13px] font-medium justify-start gap-2 text-[#111827]"
            >
              <Download className="size-3.5" />
              {t('common.download', { defaultValue: '下载' })}
            </DropdownMenuItem>
          )}
          <ConfirmDeleteDialog onOk={handleRemove}>
            <DropdownMenuItem
              onSelect={(event) => event.preventDefault()}
              disabled={isRunning}
              justifyBetween={false}
              className="text-[13px] font-medium justify-start gap-2 text-[#dc2626] focus:text-[#dc2626]"
            >
              <Trash2 className="size-3.5" />
              {t('common.delete', { defaultValue: '删除' })}
            </DropdownMenuItem>
          </ConfirmDeleteDialog>
        </DropdownMenuContent>
      </DropdownMenu>

      <Dialog open={viewOpen} onOpenChange={setViewOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>
              {t('common.view', { defaultValue: '查看' })} - {record.name}
            </DialogTitle>
          </DialogHeader>
          <div className="grid grid-cols-[108px_1fr] gap-x-2 gap-y-2 text-sm">
            {Object.entries(record)
              .filter(([key]) => Fields.includes(key))
              .map(([key, value]) => {
                const renderedValue =
                  key in FunctionMap
                    ? FunctionMap[key as keyof typeof FunctionMap](value)
                    : value;

                return (
                  <Fragment key={key}>
                    <div className="text-[#6b7280]">{key}</div>
                    <div className="text-[#111827] break-all whitespace-pre-wrap">
                      {String(renderedValue ?? '')}
                    </div>
                  </Fragment>
                );
              })}
          </div>
        </DialogContent>
      </Dialog>
    </section>
  );
}
