import { UploadFormSchemaType } from '@/components/file-upload-dialog';
import { useSetModalState } from '@/hooks/common-hooks';
import {
  useRunDocument,
  useUploadNextDocument,
} from '@/hooks/use-document-request';
import kbService from '@/services/knowledge-service';
import { useCallback, useState } from 'react';

const MAX_BATCH_FILES = 200;
const MAX_PARALLEL_BATCHES = 3;

export const useHandleUploadDocument = () => {
  const {
    visible: documentUploadVisible,
    hideModal: hideDocumentUploadModal,
    showModal: showDocumentUploadModal,
  } = useSetModalState();
  const [isUploading, setIsUploading] = useState(false);
  const { uploadDocument, loading, invalidateDocumentList } =
    useUploadNextDocument();
  const { runDocumentByIds } = useRunDocument({
    silent: true,
    skipInvalidate: true,
  });

  const onDocumentUploadOk = useCallback(
    async ({ fileList, reviewBeforeChunk }: UploadFormSchemaType) => {
      if (fileList.length === 0) {
        return;
      }

      const uploadBatches: File[][] = [];
      for (let i = 0; i < fileList.length; i += MAX_BATCH_FILES) {
        uploadBatches.push(fileList.slice(i, i + MAX_BATCH_FILES));
      }

      let nextBatchIndex = 0;
      let totalSuccess = 0;
      let lastCode = 500;
      const reviewDocIds: string[] = [];
      const autoRunDocIds: string[] = [];

      setIsUploading(true);
      try {
        const workerCount = Math.min(
          MAX_PARALLEL_BATCHES,
          uploadBatches.length,
        );
        const workers = Array.from({ length: workerCount }, async () => {
          while (true) {
            const currentIndex = nextBatchIndex;
            nextBatchIndex += 1;
            if (currentIndex >= uploadBatches.length) {
              return;
            }

            const ret = await uploadDocument(uploadBatches[currentIndex], {
              shouldInvalidate: false,
              reviewBeforeChunk: Boolean(reviewBeforeChunk),
            });
            if (!ret) {
              continue;
            }

            lastCode = ret.code ?? lastCode;
            const docs = Array.isArray(ret.data) ? ret.data : [];
            totalSuccess += docs.length;

            if (docs.length > 0) {
              const reviewIds = docs
                .filter(
                  (doc: any) =>
                    doc?.parser_config?.ocr_review?.review_required === true,
                )
                .map((doc: any) => doc.id);
              const autoRunIds = docs
                .filter(
                  (doc: any) =>
                    doc?.parser_config?.ocr_review?.review_required !== true,
                )
                .map((doc: any) => doc.id);
              reviewDocIds.push(...reviewIds);
              autoRunDocIds.push(...autoRunIds);
            }
          }
        });

        await Promise.all(workers);

        const uniqueReviewDocIds = Array.from(new Set(reviewDocIds));
        const uniqueAutoRunDocIds = Array.from(new Set(autoRunDocIds));
        if (uniqueAutoRunDocIds.length > 0) {
          await runDocumentByIds({
            documentIds: uniqueAutoRunDocIds,
            run: 1,
            shouldDelete: false,
          });
        }

        invalidateDocumentList();

        if (totalSuccess > 0) {
          hideDocumentUploadModal();
          if (uniqueReviewDocIds.length > 0) {
            // Run OCR review initialization in background so UI is not blocked.
            void kbService
              .ocr_review_init({
                doc_ids: uniqueReviewDocIds,
              })
              .finally(() => {
                invalidateDocumentList();
              });
          }
          return 0;
        }

        if (uniqueReviewDocIds.length > 0) {
          void kbService.ocr_review_init({
            doc_ids: uniqueReviewDocIds,
          });
        }
        return lastCode;
      } finally {
        setIsUploading(false);
      }
    },
    [
      hideDocumentUploadModal,
      invalidateDocumentList,
      runDocumentByIds,
      uploadDocument,
    ],
  );

  return {
    documentUploadLoading: loading || isUploading,
    onDocumentUploadOk,
    documentUploadVisible,
    hideDocumentUploadModal,
    showDocumentUploadModal,
  };
};
