import { FileIcon } from '@/components/icon-font';
import {
  FilterType,
  FilterValue,
} from '@/components/list-filter-bar/interface';
import { Button } from '@/components/ui/button';
import { Checkbox } from '@/components/ui/checkbox';
import {
  DropdownMenu,
  DropdownMenuCheckboxItem,
  DropdownMenuContent,
  DropdownMenuLabel,
  DropdownMenuSeparator,
  DropdownMenuTrigger,
} from '@/components/ui/dropdown-menu';
import { Switch } from '@/components/ui/switch';
import {
  Tooltip,
  TooltipContent,
  TooltipTrigger,
} from '@/components/ui/tooltip';
import { useNavigatePage } from '@/hooks/logic-hooks/navigate-hooks';
import { useSetDocumentStatus } from '@/hooks/use-document-request';
import { IDocumentInfo } from '@/interfaces/database/document';
import { cn } from '@/lib/utils';
import { formatFileSize } from '@/utils/common-util';
import { formatDate } from '@/utils/date';
import { ColumnDef } from '@tanstack/table-core';
import { ArrowUpDown, ListFilter } from 'lucide-react';
import { useTranslation } from 'react-i18next';
import { DatasetActionCell } from './dataset-action-cell';
import { ParsingMethodCell } from './parsing-method-cell';
import { ParsingStatusCell } from './parsing-status-cell';
import { UseChangeDocumentParserShowType } from './use-change-document-parser';
import { UseRenameDocumentShowType } from './use-rename-document';
import { UseSaveMetaShowType } from './use-save-meta';

type UseDatasetTableColumnsType = UseChangeDocumentParserShowType &
  UseRenameDocumentShowType &
  UseSaveMetaShowType & {
    runStatusFilters: FilterType[];
    filterValue: FilterValue;
    handleFilterSubmit(value: FilterValue): void;
  };

export function useDatasetTableColumns({
  showChangeParserModal,
  showRenameModal,
  showSetMetaModal,
  runStatusFilters,
  filterValue,
  handleFilterSubmit,
}: UseDatasetTableColumnsType) {
  const { t: tCommon } = useTranslation();
  const { t } = useTranslation('translation', {
    keyPrefix: 'knowledgeDetails',
  });

  const { navigateToChunkParsedResult } = useNavigatePage();
  const { setDocumentStatus } = useSetDocumentStatus();
  const columnName = t('name', { defaultValue: '名称' });
  const columnSize = t('fileSize', { defaultValue: '文件大小' });
  const columnChunk = t('chunkNumber', { defaultValue: '分块数' });
  const columnParseMethod = t('chunkMethod', { defaultValue: '解析方法' });
  const columnParseStatus = t('Parse', { defaultValue: '解析状态' });
  const columnEnabled = t('enabled', { defaultValue: '启用' });
  const columnUploadDate = t('uploadDate', { defaultValue: '上传日期' });
  const columnAction = '操作';
  const selectedRunStatus = filterValue.run ?? [];
  const runStatusIds = runStatusFilters.map((item) => item.id);

  const handleRunStatusChange = (nextRun: string[]) => {
    handleFilterSubmit({
      ...filterValue,
      run: nextRun,
    });
  };

  const columns: ColumnDef<IDocumentInfo>[] = [
    {
      id: 'select',
      header: ({ table }) => (
        <Checkbox
          checked={
            table.getIsAllPageRowsSelected() ||
            (table.getIsSomePageRowsSelected() && 'indeterminate')
          }
          onCheckedChange={(value) => table.toggleAllPageRowsSelected(!!value)}
          aria-label="Select all"
        />
      ),
      cell: ({ row }) => (
        <Checkbox
          checked={row.getIsSelected()}
          onCheckedChange={(value) => row.toggleSelected(!!value)}
          aria-label="Select row"
        />
      ),
      enableSorting: false,
      enableHiding: false,
    },
    {
      accessorKey: 'name',
      header: ({ column }) => {
        return (
          <Button
            variant="transparent"
            className="border-none px-0 text-[#6b7280] hover:text-[#111827]"
            onClick={() => column.toggleSorting(column.getIsSorted() === 'asc')}
          >
            {columnName}
            <ArrowUpDown className="size-3.5" />
          </Button>
        );
      },
      meta: { cellClassName: 'max-w-[26vw]' },
      cell: ({ row }) => {
        const name: string = row.getValue('name');

        return (
          <Tooltip>
            <TooltipTrigger asChild>
              <div
                className="flex gap-2 cursor-pointer items-start"
                onClick={navigateToChunkParsedResult(
                  row.original.id,
                  row.original.kb_id,
                )}
              >
                <FileIcon name={name}></FileIcon>
                <div className="min-w-0">
                  <div className={cn('truncate font-medium text-[#111827]')}>
                    {name}
                  </div>
                  <div className="text-xs text-[#9ca3af] mt-0.5 truncate">
                    ID:{row.original.id}
                  </div>
                </div>
              </div>
            </TooltipTrigger>
            <TooltipContent>
              <p>{name}</p>
            </TooltipContent>
          </Tooltip>
        );
      },
    },
    {
      accessorKey: 'size',
      header: ({ column }) => {
        return (
          <Button
            variant="transparent"
            className="border-none px-0 text-[#6b7280] hover:text-[#111827]"
            onClick={() => column.toggleSorting(column.getIsSorted() === 'asc')}
          >
            {columnSize}
            <ArrowUpDown className="size-3.5" />
          </Button>
        );
      },
      cell: ({ row }) => (
        <div>{formatFileSize(Number(row.getValue('size')))}</div>
      ),
    },
    {
      accessorKey: 'chunk_num',
      header: columnChunk,
      cell: ({ row }) => (
        <div className="capitalize">{row.getValue('chunk_num')}</div>
      ),
    },
    {
      accessorKey: 'parser_id',
      header: columnParseMethod,
      cell: ({ row }) => (
        <ParsingMethodCell
          record={row.original}
          showChangeParserModal={showChangeParserModal}
          showSetMetaModal={showSetMetaModal}
        />
      ),
    },
    {
      accessorKey: 'run',
      header: (
        <DropdownMenu>
          <DropdownMenuTrigger asChild>
            <Button
              variant="transparent"
              className="border-none px-0 text-[#6b7280] hover:text-[#111827]"
            >
              {columnParseStatus}
              <ListFilter className="size-3.5" />
            </Button>
          </DropdownMenuTrigger>
          <DropdownMenuContent align="start" className="w-44 p-1.5">
            <DropdownMenuLabel className="px-2 py-1 text-xs text-[#9ca3af]">
              {columnParseStatus}
            </DropdownMenuLabel>
            <DropdownMenuSeparator />
            <DropdownMenuCheckboxItem
              checked={
                runStatusIds.length > 0 &&
                selectedRunStatus.length === runStatusIds.length
              }
              onSelect={(event) => event.preventDefault()}
              onCheckedChange={(checked) =>
                handleRunStatusChange(checked ? runStatusIds : [])
              }
              className="py-2"
            >
              {tCommon('common.selectAll', { defaultValue: '全选' })}
            </DropdownMenuCheckboxItem>
            {runStatusFilters.map((item) => (
              <DropdownMenuCheckboxItem
                key={item.id}
                checked={selectedRunStatus.includes(item.id)}
                onSelect={(event) => event.preventDefault()}
                onCheckedChange={(checked) => {
                  const next = checked
                    ? [...selectedRunStatus, item.id]
                    : selectedRunStatus.filter((x) => x !== item.id);
                  handleRunStatusChange(Array.from(new Set(next)));
                }}
                className="py-2"
              >
                <span className="inline-flex items-center justify-between w-full pr-1">
                  <span>{item.label}</span>
                  <span className="text-xs text-[#9ca3af]">{item.count}</span>
                </span>
              </DropdownMenuCheckboxItem>
            ))}
          </DropdownMenuContent>
        </DropdownMenu>
      ),
      cell: ({ row }) => {
        return <ParsingStatusCell record={row.original}></ParsingStatusCell>;
      },
    },
    {
      accessorKey: 'status',
      header: columnEnabled,
      cell: ({ row }) => {
        const id = row.original.id;
        const enabled = row.getValue('status') === '1';
        return (
          <div className="flex items-center">
            <Switch
              checked={enabled}
              onCheckedChange={(e) => {
                setDocumentStatus({ status: e, documentId: id });
              }}
            />
          </div>
        );
      },
    },
    {
      accessorKey: 'create_time',
      header: ({ column }) => {
        return (
          <Button
            variant="transparent"
            className="border-none px-0 text-[#6b7280] hover:text-[#111827]"
            onClick={() => column.toggleSorting(column.getIsSorted() === 'asc')}
          >
            {columnUploadDate}
            <ArrowUpDown className="size-3.5" />
          </Button>
        );
      },
      cell: ({ row }) => <div>{formatDate(row.getValue('create_time'))}</div>,
    },
    {
      id: 'actions',
      header: columnAction,
      enableHiding: false,
      cell: ({ row }) => {
        const record = row.original;

        return (
          <DatasetActionCell
            record={record}
            showRenameModal={showRenameModal}
          ></DatasetActionCell>
        );
      },
    },
  ];

  return columns;
}
